import threading, queue, time
q = queue.Queue()
res = []
def producer(id):
    for i in range(5):
        q.put(id * 10 + i)
        time.sleep(0.001)
def consumer():
    while True:
        try:
            item = q.get(timeout=0.1)
            res.append(item)
            q.task_done()
        except queue.Empty:
            break

prods = [threading.Thread(target=producer, args=(1,)), threading.Thread(target=producer, args=(2,))]
cons = [threading.Thread(target=consumer), threading.Thread(target=consumer)]

for t in prods + cons: t.start()
for t in prods: t.join()
q.join()
print(f'Items consumed: {len(res)}')
print(f'Expected sum: {sum(res) == sum(10 + i for i in range(5)) + sum(20 + i for i in range(5))}')

import threading
counter = 0
lock = threading.Lock()
def increment():
    global counter
    for _ in range(1000):
        with lock:
            counter += 1
threads = [threading.Thread(target=increment) for _ in range(10)]
for t in threads: t.start()
for t in threads: t.join()
print(f'Final counter (thread-safe): {counter}')
